import React, { useState, useRef, useEffect } from 'react';
import { ChevronsLeftRight, Check, X } from 'lucide-react';

const Transformation: React.FC = () => {
  const [sliderPosition, setSliderPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMove = (event: React.MouseEvent | React.TouchEvent | MouseEvent | TouchEvent) => {
    if (!isDragging || !containerRef.current) return;

    let clientX;
    if ('touches' in event) {
      clientX = event.touches[0].clientX;
    } else {
      clientX = (event as any).clientX;
    }

    const rect = containerRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(clientX - rect.left, rect.width));
    const percentage = (x / rect.width) * 100;

    setSliderPosition(percentage);
  };

  const handleMouseDown = () => setIsDragging(true);
  const handleMouseUp = () => setIsDragging(false);

  useEffect(() => {
    const handleGlobalMouseUp = () => setIsDragging(false);
    const handleGlobalMouseMove = (e: MouseEvent | TouchEvent) => handleMove(e);

    if (isDragging) {
      window.addEventListener('mouseup', handleGlobalMouseUp);
      window.addEventListener('touchend', handleGlobalMouseUp);
      window.addEventListener('mousemove', handleGlobalMouseMove);
      window.addEventListener('touchmove', handleGlobalMouseMove);
    }

    return () => {
      window.removeEventListener('mouseup', handleGlobalMouseUp);
      window.removeEventListener('touchend', handleGlobalMouseUp);
      window.removeEventListener('mousemove', handleGlobalMouseMove);
      window.removeEventListener('touchmove', handleGlobalMouseMove);
    };
  }, [isDragging]);

  return (
    <section className="py-24 relative transition-colors duration-700" 
      style={{ backgroundColor: sliderPosition > 55 ? '#134e4a' : '#1e293b' }}>

      <div className="container mx-auto px-6">
        <div className="text-center mb-12">
            <h2 className="text-3xl md:text-4xl font-bold text-white mb-4">
                Van Chaos naar Controle
            </h2>
            <p className="text-slate-300">Sleep de slider en zie het verschil.</p>
        </div>

        <div 
          ref={containerRef}
          className="relative w-full max-w-5xl mx-auto aspect-[16/9] rounded-2xl overflow-hidden border-4 border-white/10 shadow-2xl select-none cursor-ew-resize"
          onMouseDown={handleMouseDown}
          onTouchStart={handleMouseDown}
        >
          {/* BEFORE IMAGE (Bottom Layer) */}
          <div className="absolute inset-0 bg-slate-200 flex flex-col">
            {/* Mocking a messy desktop via CSS/HTML to avoid external images matching the exact prompt need */}
            <div className="h-6 bg-slate-300 border-b border-slate-400 flex items-center px-2 gap-1">
                <div className="w-2 h-2 rounded-full bg-red-500"></div>
                <div className="w-2 h-2 rounded-full bg-yellow-500"></div>
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
            </div>
            <div className="flex-1 p-4 relative overflow-hidden">
                 {/* Floating messy windows */}
                 {[1,2,3,4,5].map((i) => (
                     <div key={i} className="absolute bg-white shadow-xl rounded-lg border border-slate-300 p-2" 
                          style={{
                              top: `${20 + i * 10}%`, 
                              left: `${10 + i * 12}%`,
                              width: '300px',
                              height: '200px',
                              zIndex: i
                          }}>
                        <div className="h-4 bg-red-100 mb-2 w-full flex items-center justify-between px-1">
                            <span className="text-[8px] text-red-800">Connection Error</span>
                            <X className="w-3 h-3 text-red-800"/>
                        </div>
                        <div className="space-y-2">
                            <div className="h-2 bg-slate-100 w-3/4 rounded"></div>
                            <div className="h-2 bg-slate-100 w-1/2 rounded"></div>
                        </div>
                     </div>
                 ))}
                 <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 bg-red-500/90 text-white p-4 rounded-lg shadow-2xl z-50 animate-pulse">
                     <AlertTriangle className="w-12 h-12 mx-auto mb-2"/>
                     <div className="font-bold text-center">SYSTEM OVERLOAD</div>
                 </div>
            </div>
            <div className="absolute bottom-4 left-4 bg-black/50 text-white px-3 py-1 rounded-full text-sm backdrop-blur-md">
                Huidige Situatie
            </div>
          </div>

          {/* AFTER IMAGE (Top Layer - Clipped) */}
          <div 
            className="absolute inset-0 bg-navy-900 border-r border-teal-500/50"
            style={{ width: `${sliderPosition}%` }}
          >
             <div className="h-full w-full relative bg-navy-900 flex flex-col">
                {/* Clean Dashboard Header */}
                <div className="h-16 border-b border-white/5 flex items-center px-6 justify-between bg-navy-800/50">
                    <div className="flex items-center gap-4">
                        <div className="w-8 h-8 bg-teal-500 rounded-lg flex items-center justify-center font-bold text-white">ZG</div>
                        <nav className="flex gap-4 text-sm text-slate-300">
                            <span className="text-white font-medium">Dashboard</span>
                            <span>Cliënten</span>
                            <span>Agenda</span>
                        </nav>
                    </div>
                    <div className="flex items-center gap-2">
                         <div className="w-8 h-8 rounded-full bg-slate-700"></div>
                    </div>
                </div>

                {/* Clean Dashboard Content */}
                <div className="p-8 grid grid-cols-3 gap-6">
                    <div className="col-span-2 bg-white/5 rounded-xl p-6 border border-white/5">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-white font-medium">Omzet Overzicht</h3>
                            <select className="bg-black/20 text-xs text-slate-400 rounded px-2 py-1 border-none outline-none"><option>Deze week</option></select>
                        </div>
                        <div className="h-32 flex items-end justify-between gap-2">
                            {[40, 60, 45, 70, 85, 65, 90].map((h, i) => (
                                <div key={i} className="w-full bg-teal-500/20 rounded-t-sm relative group">
                                    <div className="absolute bottom-0 w-full bg-teal-500 rounded-t-sm transition-all duration-500" style={{height: `${h}%`}}></div>
                                </div>
                            ))}
                        </div>
                    </div>
                    <div className="space-y-4">
                        <div className="bg-white/5 rounded-xl p-4 border border-white/5 flex items-center gap-3">
                            <div className="w-10 h-10 rounded-full bg-green-500/10 flex items-center justify-center text-green-400"><Check size={18}/></div>
                            <div>
                                <div className="text-xs text-slate-400">Nieuwe inschrijving</div>
                                <div className="text-sm text-white font-medium">Anouk J.</div>
                            </div>
                        </div>
                        <div className="bg-white/5 rounded-xl p-4 border border-white/5 flex items-center gap-3">
                             <div className="w-10 h-10 rounded-full bg-blue-500/10 flex items-center justify-center text-blue-400"><Check size={18}/></div>
                            <div>
                                <div className="text-xs text-slate-400">Call ingepland</div>
                                <div className="text-sm text-white font-medium">Peter B.</div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="absolute bottom-4 right-4 bg-teal-500/90 text-white px-3 py-1 rounded-full text-sm backdrop-blur-md shadow-lg shadow-teal-500/20">
                    Zichtbare Groei Dashboard
                </div>
             </div>
          </div>

          {/* Slider Handle */}
          <div 
            className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize z-20 shadow-[0_0_20px_rgba(255,255,255,0.5)]"
            style={{ left: `${sliderPosition}%` }}
          >
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-lg text-navy-900 hover:scale-110 transition-transform">
              <ChevronsLeftRight className="w-6 h-6" />
            </div>
          </div>
        </div>
