const PricingCalculator: React.FC = () => {
  const [costs, setCosts] = useState<{ [key: string]: number }>(
    defaultCosts.reduce((acc, item) => ({ ...acc, [item.label]: item.defaultCost }), {})
  );

  const totalCurrentCost = useMemo(() => Object.values(costs).reduce((a, b) => a + b, 0), [costs]);
  const zgCost = 197;
  const savings = totalCurrentCost - zgCost;

  const handleCostChange = (label: string, value: string) => {
    const num = parseInt(value) || 0;
    setCosts(prev => ({ ...prev, [label]: num }));
  };

  return (
    <section className="py-24 bg-navy-950 relative">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-navy-800/50 via-navy-950 to-navy-950"></div>

