          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
            <div className="space-y-4">
              {defaultCosts.map((item) => (
                <div key={item.label} className="flex items-center justify-between group">
                  <label className="text-slate-300 text-sm font-medium">{item.label}</label>
                  <div className="flex items-center">
                    <span className="text-slate-500 mr-2">€</span>
                    <input 
                      type="number" 
                      value={costs[item.label]} 
                      onChange={(e) => handleCostChange(item.label, e.target.value)}
                      className="w-20 bg-navy-800 border border-white/10 rounded px-2 py-1 text-white text-right focus:border-teal-500 focus:outline-none transition-colors"
                    />
                  </div>
                </div>
              ))}
              <div className="h-px bg-white/10 my-4"></div>
              <div className="flex justify-between items-center text-slate-300 font-medium">
                <span>Je huidige totaal:</span>
                <span>€{totalCurrentCost} /mnd</span>
              </div>
            </div>

            <div className="bg-teal-500/10 rounded-2xl p-8 text-center border border-teal-500/20 relative overflow-hidden">
               {/* Shine effect */}
               <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-white/5 to-transparent pointer-events-none"></div>

               <p className="text-teal-200 text-sm uppercase tracking-wide font-semibold mb-2">Jouw maandelijkse winst</p>
               <div className="text-5xl font-bold text-teal-400 mb-2 transition-all duration-300">
                 €{Math.max(0, savings)}
               </div>
               <p className="text-slate-400 text-sm">per maand extra in je zak</p>

               {savings > 0 && (
                   <div className="mt-6 inline-block px-4 py-2 bg-teal-500 text-navy-900 font-bold rounded-full text-sm animate-pulse">
                       Dat is €{savings * 12} per jaar!
                   </div>
               )}
            </div>
          </div>
        </div>

        {/* Pricing Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-start">
            {tiers.map((tier, index) => (
                <div 
                    key={tier.name}
                    className={`relative rounded-3xl p-8 border transition-all duration-300 ${
                        tier.highlight 
                        ? 'bg-navy-800 border-teal-500 shadow-[0_0_40px_rgba(20,184,166,0.15)] transform scale-105 z-10' 
                        : 'bg-navy-900 border-white/5 hover:border-white/20 opacity-90 hover:opacity-100'
                    }`}
                >
                    {tier.highlight && (
                        <div className="absolute -top-4 left-1/2 transform -translate-x-1/2 bg-teal-500 text-navy-900 text-xs font-bold px-4 py-1 rounded-full flex items-center gap-1 shadow-lg">
                            <Sparkles size={12} /> MEEST GEKOZEN
                        </div>
                    )}

                    <h3 className={`text-xl font-bold mb-2 ${tier.highlight ? 'text-white' : 'text-slate-200'}`}>{tier.name}</h3>
                    <p className="text-slate-400 text-sm mb-6 h-10">{tier.description}</p>

                    <div className="flex items-baseline mb-8">
                        <span className="text-4xl font-bold text-white">€{tier.price}</span>
                        <span className="text-slate-500 ml-1">{tier.period}</span>
                    </div>

                    <ul className="space-y-4 mb-8">
                        {tier.features.map((feat, i) => (
                            <li key={i} className="flex items-start gap-3 text-sm text-slate-300">
                                <div className={`mt-0.5 w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${tier.highlight ? 'bg-teal-500/20 text-teal-400' : 'bg-slate-700 text-slate-400'}`}>
