          </h2>

          <div className="bg-navy-800/50 inline-block p-6 rounded-2xl border border-white/10 backdrop-blur-sm mb-8">
            <p className="text-slate-400 text-sm uppercase tracking-wide mb-2">Bonus Aanbod Verloopt Over:</p>
            <div className="flex gap-4 justify-center text-white font-mono text-2xl md:text-3xl font-bold">
               <div className="flex flex-col">
                   <span>0{timeLeft.hours}</span>
                   <span className="text-[10px] text-slate-500 font-sans font-normal">UUR</span>
               </div>
               <span>:</span>
               <div className="flex flex-col">
                   <span>{timeLeft.minutes < 10 ? `0${timeLeft.minutes}` : timeLeft.minutes}</span>
                   <span className="text-[10px] text-slate-500 font-sans font-normal">MIN</span>
               </div>
               <span>:</span>
               <div className="flex flex-col">
                   <span className="text-teal-400">{timeLeft.seconds < 10 ? `0${timeLeft.seconds}` : timeLeft.seconds}</span>
                   <span className="text-[10px] text-slate-500 font-sans font-normal">SEC</span>
