            </div>
            <p className="text-gold-400 text-sm mt-2 font-medium">✨ Gratis Onboarding Call t.w.v. €200</p>
          </div>

          <div>
             <button className="px-10 py-5 bg-teal-500 hover:bg-teal-400 text-navy-900 text-lg font-bold rounded-xl transition-all shadow-[0_0_30px_rgba(20,184,166,0.3)] hover:shadow-[0_0_50px_rgba(20,184,166,0.5)] flex items-center gap-2 mx-auto">
                Start Je Gratis Demo
                <ArrowRight className="w-6 h-6" />
              </button>
          </div>
        </div>

        {/* Footer Links */}
