            const spread = 120; // Max spread in pixels
            const xPos = (i - (cards.length - 1) / 2) * (spread + (mousePos * 50));
            const rotation = (i - (cards.length - 1) / 2) * (5 + (mousePos * 20));
            const zIndex = hoverIndex === i ? 50 : i;

            return (
              <div 
                key={i}
                onMouseEnter={() => setHoverIndex(i)}
                onMouseLeave={() => setHoverIndex(null)}
                className="absolute w-64 h-80 glass-prism rounded-[2.5rem] p-8 border-white/10 shadow-3xl transition-all duration-500 ease-out cursor-pointer hover:border-primary/50"
                style={{
                  transform: `translateX(${xPos}px) rotate(${rotation}deg) ${hoverIndex === i ? 'scale(1.15) translateY(-40px)' : 'translateY(0)'}`,
                  zIndex: zIndex,
                  opacity: hoverIndex !== null && hoverIndex !== i ? 0.3 : 1,
                }}
              >
                <div className={`w-14 h-14 rounded-2xl bg-white/5 flex items-center justify-center ${card.color} mb-12`}>
                   <card.icon size={28} />
                </div>
                <div className="space-y-2">
