interface GlowCardProps {
  children: React.ReactNode;
  className?: string;
  hoverGradient: string;
}

const GlowCard: React.FC<GlowCardProps> = ({ children, className = "", hoverGradient }) => {
  const divRef = useRef<HTMLDivElement>(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!divRef.current) return;
    const rect = divRef.current.getBoundingClientRect();
    setPosition({ x: e.clientX - rect.left, y: e.clientY - rect.top });
  };

  return (
    <div
      ref={divRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={`relative rounded-[2.5rem] overflow-hidden bg-white/[0.02] border border-white/[0.08] transition-all duration-500 group ${className}`}
    >
      {/* Immersive Hover Background */}
      <div
        className="absolute inset-0 transition-opacity duration-1000 opacity-0 group-hover:opacity-100"
        style={{
          background: `radial-gradient(1000px circle at ${position.x}px ${position.y}px, ${hoverGradient}, transparent 70%)`,
        }}
      />

      <div className="relative h-full z-10 p-10 flex flex-col">
        {children}
      </div>
    </div>
  );
};

